import{_ as t,a,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/blog.md","filePath":"en/Other/blog.md","lastUpdated":1781962217000}'),p={name:"en/Other/blog.md"};function r(d,e,c,g,h,u){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>The blog feature adds a standalone blog page to your ImgBed site.</p><p>After it is enabled, visitors can open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog homepage" loading="lazy"></p><p>The blog is adapted from the open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> project. ImgBed rewrites and integrates it with Vue so it can run as part of the image hosting site.</p><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Blog settings are under:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>Turn on <code>Enable</code>.</li><li>Select the GitHub account used to store blog configuration.</li><li>Click <code>Update Blog</code>.</li><li>Wait for the success message.</li><li>Open <code>https://your-domain.com/blog/</code> to view the blog.</li></ol><p>On first use, ImgBed prepares a private GitHub repository under the selected account:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>This repository stores blog settings and article content.</p><h2 id="writing-posts" tabindex="-1">Writing Posts <a class="header-anchor" href="#writing-posts" aria-label="Permalink to &quot;Writing Posts&quot;">​</a></h2><p>Edit blog posts in your private GitHub repository:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typical workflow:</p><ol><li>Open GitHub.</li><li>Enter the private <code>imgbed-blog-config</code> repository.</li><li>Edit or add post files.</li><li>Commit the changes.</li><li>Return to the ImgBed admin panel and click <code>Update Blog</code>, or click the logo in the upper-left corner of the blog homepage three times to trigger a blog update.</li></ol><p><code>Update Blog</code> does not overwrite content you have written. It initializes the repository when needed and refreshes blog cache.</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>The blog supports common blog features such as post lists, categories, tags, archives, search, dark mode, and language switching.</p><p>It also supports comments and visit statistics.</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>Comments appear below posts. Visitors can submit an avatar, nickname, email, and comment content.</p><p>Visit statistics show post views and site visits, helping you understand blog traffic.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>The blog is always served under <code>/blog/</code>.</p><p>For example, if your ImgBed domain is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>The blog URL is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>After the blog is disabled, visitors can no longer access the blog page.</p>',34)])])}const f=i(p,[["render",r]]);export{v as __pageData,f as default};
